{"content": "/* =============================================================
   /flow2 — View Transitions scopeadas al panel de contenido
   =============================================================

   Estrategia:
   - El wrapper del contenido tiene `view-transition-name: content`
     (asignado con use:transition={'content'} en +layout.svelte).
   - Mientras el layout de /flow2 está montado, <html> lleva la clase
     `flow2-active`, que desactiva la captura del "root". Así el sidebar
     y el header NO se animan: sólo el panel de contenido.
   - El grupo `content` se recorta (overflow: clip) para que ninguna
     animación (slides, parallax…) se desborde hacia el sidebar.
   - El tipo de animación se elige aplicando una clase al <html>
     (fade, push, circle…) más la dirección (forward/backward),
     controladas desde flow-nav.svelte.ts.
   ============================================================= */

/* Desactiva la transición del root SOLO mientras estamos en /flow2. */
html.flow2-active::view-transition-old(root),
html.flow2-active::view-transition-new(root) {
	animation: none;
	mix-blend-mode: normal;
	display: none;
}

/* El panel de contenido es el único grupo que anima, y queda recortado. */
::view-transition-group(content) {
	overflow: clip;
}

/* Ajustes base de las imágenes del grupo `content`. */
::view-transition-old(content),
::view-transition-new(content) {
	animation-duration: 0.4s;
	animation-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
	animation-fill-mode: both;
	/* ambas capas se solapan dentro de la caja del panel */
	height: 100%;
	width: 100%;
}

/* La capa entrante se dibuja por encima de la saliente. */
::view-transition-new(content) {
	z-index: 1;
}

/* ============= FADE ============= */
html.fade::view-transition-old(content) {
	animation-name: vt-fade-out;
}
html.fade::view-transition-new(content) {
	animation-name: vt-fade-in;
}

/* ============= PUSH ============= */
html.push.forward::view-transition-old(content) {
	animation-name: vt-slide-out-left;
}
html.push.forward::view-transition-new(content) {
	animation-name: vt-slide-in-right;
}
html.push.backward::view-transition-old(content) {
	animation-name: vt-slide-out-right;
}
html.push.backward::view-transition-new(content) {
	animation-name: vt-slide-in-left;
}

/* ============= CIRCLE ============= */
html.circle::view-transition-old(content) {
	animation-name: vt-fade-out;
}
html.circle::view-transition-new(content) {
	animation-name: vt-circle-in;
	animation-duration: 0.7s;
}

/* ============= FLIP ============= */
html.flip::view-transition-old(content) {
	animation-name: vt-flip-out;
	animation-duration: 0.6s;
	transform-origin: center center;
}
html.flip::view-transition-new(content) {
	animation-name: vt-flip-in;
	animation-duration: 0.6s;
	transform-origin: center center;
}

/* ============= COVER ============= */
html.cover::view-transition-old(content) {
	animation-name: vt-cover-out;
	animation-duration: 0.45s;
}
html.cover::view-transition-new(content) {
	animation-name: vt-cover-in;
	animation-duration: 0.45s;
}

/* ============= DIVE ============= */
html.dive::view-transition-old(content) {
	animation-name: vt-dive-out;
	animation-duration: 0.5s;
}
html.dive::view-transition-new(content) {
	animation-name: vt-dive-in;
	animation-duration: 0.5s;
}

/* ============= PARALLAX ============= */
html.parallax.forward::view-transition-old(content) {
	animation-name: vt-parallax-out-fwd;
}
html.parallax.forward::view-transition-new(content) {
	animation-name: vt-slide-in-right;
}
html.parallax.backward::view-transition-old(content) {
	animation-name: vt-slide-out-right;
}
html.parallax.backward::view-transition-new(content) {
	animation-name: vt-parallax-in-bwd;
}

/* ============= iOS SLIDE ============= */
html.ios-slide.forward::view-transition-old(content) {
	animation-name: vt-ios-out-fwd;
	animation-timing-function: cubic-bezier(0.32, 0.72, 0, 1);
	animation-duration: 0.4s;
}
html.ios-slide.forward::view-transition-new(content) {
	animation-name: vt-slide-in-right;
	animation-timing-function: cubic-bezier(0.32, 0.72, 0, 1);
	animation-duration: 0.4s;
}
html.ios-slide.backward::view-transition-old(content) {
	animation-name: vt-slide-out-right;
	animation-timing-function: cubic-bezier(0.32, 0.72, 0, 1);
	animation-duration: 0.4s;
}
html.ios-slide.backward::view-transition-new(content) {
	animation-name: vt-ios-in-bwd;
	animation-timing-function: cubic-bezier(0.32, 0.72, 0, 1);
	animation-duration: 0.4s;
}

/* ============= ANDROID FADE ============= */
html.android-fade::view-transition-old(content) {
	animation-name: vt-fade-out;
	animation-duration: 0.3s;
}
html.android-fade::view-transition-new(content) {
	animation-name: vt-android-in;
	animation-duration: 0.3s;
	animation-timing-function: cubic-bezier(0.4, 0, 0.2, 1);
}

/* ============= KEYFRAMES ============= */
@keyframes vt-fade-out {
	to {
		opacity: 0;
	}
}
@keyframes vt-fade-in {
	from {
		opacity: 0;
	}
}

@keyframes vt-slide-out-left {
	to {
		transform: translateX(-100%);
	}
}
@keyframes vt-slide-in-right {
	from {
		transform: translateX(100%);
	}
}
@keyframes vt-slide-out-right {
	to {
		transform: translateX(100%);
	}
}
@keyframes vt-slide-in-left {
	from {
		transform: translateX(-100%);
	}
}

@keyframes vt-circle-in {
	from {
		clip-path: circle(0% at 50% 50%);
	}
	to {
		clip-path: circle(150% at 50% 50%);
	}
}

@keyframes vt-flip-out {
	from {
		transform: perspective(1200px) rotateY(0deg);
		opacity: 1;
	}
	to {
		transform: perspective(1200px) rotateY(90deg);
		opacity: 0;
	}
}
@keyframes vt-flip-in {
	from {
		transform: perspective(1200px) rotateY(-90deg);
		opacity: 0;
	}
	to {
		transform: perspective(1200px) rotateY(0deg);
		opacity: 1;
	}
}

@keyframes vt-cover-out {
	to {
		transform: scale(0.92);
		opacity: 0.5;
	}
}
@keyframes vt-cover-in {
	from {
		transform: translateY(100%);
	}
}

@keyframes vt-dive-out {
	to {
		transform: scale(1.3);
		opacity: 0;
	}
}
@keyframes vt-dive-in {
	from {
		transform: scale(0.7);
		opacity: 0;
	}
}

@keyframes vt-parallax-out-fwd {
	to {
		transform: translateX(-30%);
		opacity: 0.6;
	}
}
@keyframes vt-parallax-in-bwd {
	from {
		transform: translateX(-30%);
		opacity: 0.6;
	}
}

@keyframes vt-ios-out-fwd {
	to {
		transform: translateX(-30%);
	}
}
@keyframes vt-ios-in-bwd {
	from {
		transform: translateX(-30%);
	}
}

@keyframes vt-android-in {
	from {
		opacity: 0;
		transform: translateY(8vh);
	}
}

/* ============= REDUCED MOTION ============= */
@media (prefers-reduced-motion: reduce) {
	::view-transition-old(content),
	::view-transition-new(content) {
		animation-duration: 0.01ms !important;
		animation-name: vt-fade-in !important;
	}
}
