// f7-circle
.router-transition-f7-circle-forward,
.router-transition-f7-circle-backward {
  &:after {
    content: '';
    position: absolute;
    left: 50%;
    top: 50%;
    width: 100vmax;
    height: 100vmax;
    margin-left: -50vmax;
    margin-top: -50vmax;
    background: var(--f7-page-bg-color);
    z-index: 100;
  }
  .page {
    pointer-events: none;
  }
}
.router-transition-f7-circle-forward {
  &:after {
    transform: scale(0);
    border-radius: 50%;
    animation: f7-circle-circle-in 400ms forwards;
  }
  .ios &,
  .md & {
    .page-next {
      opacity: 0;
      transform: scale(0.9);
      animation: f7-circle-next-to-current 300ms forwards;
      animation-delay: 300ms;
      z-index: 150;
    }
  }
}
.router-transition-f7-circle-backward {
  &:after {
    animation: f7-circle-circle-out 300ms forwards;
    animation-delay: 350ms;
  }
  .ios &,
  .md & {
    .page-current {
      animation: f7-circle-current-to-next 700ms forwards;
      z-index: 150;
    }
  }
}
@keyframes f7-circle-circle-in {
  from {
    transform: scale(0);
    border-radius: 50%;
  }
  50% {
    border-radius: 50%;
  }
  to {
    transform: scale(1);
    border-radius: 0%;
  }
}
@keyframes f7-circle-circle-out {
  from {
    transform: scale(1);
    border-radius: 0%;
  }
  50% {
    border-radius: 50%;
  }
  to {
    transform: scale(0);
    border-radius: 50%;
  }
}
@keyframes f7-circle-next-to-current {
  from {
    transform: scale(0.9);
    opacity: 0;
  }
