/* =============================================================
   /flow2 — View Transitions scopeadas al panel de contenido
   Adaptación fiel de Framework7 para View Transitions API
   =============================================================

   Estrategia:
   - El wrapper del contenido tiene `view-transition-name: content`
   - <html> lleva `flow2-active` para desactivar animación del root
   - Solo el panel anima (sidebar y header permanecen fijos)
   - Los pseudo-elementos old/new animan las snapshots before/after
   - Cada transición framework7 está adaptada a este modelo
   ============================================================= */

/* Desactiva la transición del root SOLO en /flow2 */
html.flow2-active::view-transition-old(root),
html.flow2-active::view-transition-new(root) {
	animation: none;
	display: none;
}

/* El grupo de contenido se recorta para no invadir el sidebar */
::view-transition-group(content) {
	overflow: clip;
}

/* Base para ambas capas */
::view-transition-old(content),
::view-transition-new(content) {
	animation-fill-mode: both;
	height: 100%;
	width: 100%;
}

/* La capa entrante se dibuja encima de la saliente */
::view-transition-new(content) {
	z-index: 1;
}

/* ============= FADE (Framework7 original) ============= */
/* Ambas páginas se desvanecen en paralelo con delay a mitad */
html.fade::view-transition-old(content) {
	animation: f7-fade-out 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.fade::view-transition-new(content) {
	animation: f7-fade-in 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

/* ============= PUSH (Framework7 original) ============= */
html.push.forward::view-transition-old(content) {
	animation: f7-push-current-to-next 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.push.forward::view-transition-new(content) {
	animation: f7-push-next-to-current 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

html.push.backward::view-transition-old(content) {
	animation: f7-push-current-to-prev 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.push.backward::view-transition-new(content) {
	animation: f7-push-prev-to-current 300ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

/* ============= CIRCLE (Framework7 original) ============= */
html.circle::view-transition-old(content) {
	animation: f7-circle-old 400ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.circle::view-transition-new(content) {
	animation: f7-circle-new 400ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	animation-delay: 0ms;
}

/* ============= FLIP (Framework7 original) ============= */
html.flip.forward::view-transition-old(content) {
	animation: f7-flip-current-to-next 600ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	backface-visibility: hidden;
}
html.flip.forward::view-transition-new(content) {
	animation: f7-flip-next-to-current 600ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	backface-visibility: hidden;
}

html.flip.backward::view-transition-old(content) {
	animation: f7-flip-current-to-prev 600ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	backface-visibility: hidden;
}
html.flip.backward::view-transition-new(content) {
	animation: f7-flip-prev-to-current 600ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	backface-visibility: hidden;
}

/* ============= COVER (Framework7 original) ============= */
html.cover.forward::view-transition-old(content) {
	animation: f7-cover-current-to-prev 450ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.cover.forward::view-transition-new(content) {
	animation: f7-cover-next-to-current 450ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

html.cover.backward::view-transition-old(content) {
	animation: f7-cover-current-to-next 450ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.cover.backward::view-transition-new(content) {
	animation: f7-cover-prev-to-current 450ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

/* ============= DIVE (Framework7 original) ============= */
html.dive.forward::view-transition-old(content) {
	animation: f7-dive-current-to-next 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	perspective: 1200px;
}
html.dive.forward::view-transition-new(content) {
	animation: f7-dive-next-to-current 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	perspective: 1200px;
}

html.dive.backward::view-transition-old(content) {
	animation: f7-dive-current-to-prev 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	perspective: 1200px;
}
html.dive.backward::view-transition-new(content) {
	animation: f7-dive-prev-to-current 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
	perspective: 1200px;
}

/* ============= PARALLAX (Framework7 original) ============= */
html.parallax.forward::view-transition-old(content) {
	animation: f7-parallax-current-to-prev 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.parallax.forward::view-transition-new(content) {
	animation: f7-parallax-next-to-current 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

html.parallax.backward::view-transition-old(content) {
	animation: f7-parallax-current-to-next 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}
html.parallax.backward::view-transition-new(content) {
	animation: f7-parallax-prev-to-current 500ms cubic-bezier(0.4, 0, 0.2, 1) forwards;
}

/* ============= KEYFRAMES (Framework7 fideles) ============= */

/* FADE: ambas con 50% delay (no visible en view transitions, pero respeta timing) */
@keyframes f7-fade-out {
	from {
		opacity: 1;
	}
	50% {
		opacity: 0;
	}
	to {
		opacity: 0;
	}
}

@keyframes f7-fade-in {
	from {
		opacity: 0;
	}
	50% {
		opacity: 0;
	}
	to {
		opacity: 1;
	}
}

/* PUSH */
@keyframes f7-push-next-to-current {
	from {
		transform: translateX(100%);
	}
	to {
		transform: translateX(0%);
	}
}

@keyframes f7-push-current-to-next {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(100%);
	}
}

@keyframes f7-push-prev-to-current {
	from {
		transform: translateX(-100%);
	}
	to {
		transform: translateX(0%);
	}
}

@keyframes f7-push-current-to-prev {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(-100%);
	}
}

/* CIRCLE */
@keyframes f7-circle-old {
	from {
		opacity: 1;
	}
	to {
		opacity: 0;
	}
}

@keyframes f7-circle-new {
	from {
		opacity: 0;
		transform: scale(0.9);
		clip-path: circle(0% at 50% 50%);
	}
	40% {
		opacity: 1;
		transform: scale(1.035);
		clip-path: circle(50% at 50% 50%);
	}
	to {
		opacity: 1;
		transform: scale(1);
		clip-path: circle(150% at 50% 50%);
	}
}

/* FLIP */
@keyframes f7-flip-next-to-current {
	from {
		border-radius: 32px;
		transform: translateZ(-100vmax) rotateY(180deg);
	}
	to {
		border-radius: 0;
		transform: translateZ(0px) rotateY(0deg);
	}
}

@keyframes f7-flip-current-to-next {
	from {
		border-radius: 0px;
		transform: translateZ(0px) rotateY(0deg);
	}
	to {
		border-radius: 32px;
		transform: translateZ(-100vmax) rotateY(180deg);
	}
}

@keyframes f7-flip-prev-to-current {
	from {
		border-radius: 32px;
		transform: translateZ(-100vmax) rotateY(-180deg);
	}
	to {
		border-radius: 0px;
		transform: translateZ(0px) rotateY(0deg);
	}
}

@keyframes f7-flip-current-to-prev {
	from {
		border-radius: 0px;
		transform: translateZ(0px) rotateY(0deg);
	}
	to {
		border-radius: 32px;
		transform: translateZ(-100vmax) rotateY(-180deg);
	}
}

/* COVER */
@keyframes f7-cover-next-to-current {
	from {
		transform: translateX(100%);
	}
	to {
		transform: translateX(0%);
	}
}

@keyframes f7-cover-current-to-next {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(100%);
	}
}

@keyframes f7-cover-prev-to-current {
	from {
		transform: translateZ(-300px);
		opacity: 0.5;
	}
	to {
		transform: translateZ(0);
		opacity: 1;
	}
}

@keyframes f7-cover-current-to-prev {
	from {
		transform: translateZ(0);
		opacity: 1;
	}
	to {
		transform: translateZ(-300px);
		opacity: 0.5;
	}
}

/* DIVE */
@keyframes f7-dive-next-to-current {
	from {
		opacity: 0;
		transform: translateZ(-150px);
	}
	50% {
		opacity: 0;
	}
	to {
		opacity: 1;
		transform: translateZ(0px);
	}
}

@keyframes f7-dive-current-to-next {
	from {
		opacity: 1;
		transform: translateZ(0px);
	}
	50% {
		opacity: 0;
	}
	to {
		opacity: 0;
		transform: translateZ(-150px);
	}
}

@keyframes f7-dive-prev-to-current {
	from {
		opacity: 0;
		transform: translateZ(150px);
	}
	50% {
		opacity: 0;
	}
	to {
		opacity: 1;
		transform: translateZ(0px);
	}
}

@keyframes f7-dive-current-to-prev {
	from {
		transform: translateZ(0px);
		opacity: 1;
	}
	50% {
		opacity: 0;
	}
	to {
		opacity: 0;
		transform: translateZ(150px);
	}
}

/* PARALLAX */
@keyframes f7-parallax-next-to-current {
	from {
		transform: translateX(100%);
	}
	to {
		transform: translateX(0%);
	}
}

@keyframes f7-parallax-current-to-next {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(100%);
	}
}

@keyframes f7-parallax-prev-to-current {
	from {
		transform: translateX(-20%);
	}
	to {
		transform: translateX(0%);
	}
}

@keyframes f7-parallax-current-to-prev {
	from {
		transform: translateX(0%);
	}
	to {
		transform: translateX(-20%);
	}
}

/* ============= REDUCED MOTION ============= */
@media (prefers-reduced-motion: reduce) {
	::view-transition-old(content),
	::view-transition-new(content) {
		animation-duration: 0.01ms !important;
	}
}

